"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";

interface MonthInfo {
  m: number;
  days: number;
}

// 平年各月天数
const MONTHS_DAYS: MonthInfo[] = [
  { m: 1, days: 31 }, { m: 2, days: 28 }, { m: 3, days: 31 },
  { m: 4, days: 30 }, { m: 5, days: 31 }, { m: 6, days: 30 },
  { m: 7, days: 31 }, { m: 8, days: 31 }, { m: 9, days: 30 },
  { m: 10, days: 31 }, { m: 11, days: 30 }, { m: 12, days: 31 },
];

function dayColor(days: number): string {
  if (days === 31) return "var(--primary)"; // 蓝
  if (days === 30) return "var(--accent2)"; // 绿
  return "var(--signal-shake)"; // 橙（2 月特殊）
}

function dayLabel(days: number): string {
  if (days === 31) return "大月";
  if (days === 30) return "小月";
  return "特殊";
}

interface Option {
  label: string;
  value: string;
}
interface Question {
  q: string;
  options: Option[];
  answer: string;
}

const QUESTIONS: Question[] = [
  {
    q: "哪些月份有 31 天？",
    options: [
      { label: "1、3、5、7、8、10、12 月", value: "A" },
      { label: "4、6、9、11 月", value: "B" },
      { label: "2 月", value: "C" },
      { label: "所有月份", value: "D" },
    ],
    answer: "A",
  },
  {
    q: "哪些月份有 30 天？",
    options: [
      { label: "1、3、5、7 月", value: "A" },
      { label: "4、6、9、11 月", value: "B" },
      { label: "2 月", value: "C" },
      { label: "所有月份", value: "D" },
    ],
    answer: "B",
  },
  {
    q: "2 月有多少天？（平年）",
    options: [
      { label: "30 天", value: "A" },
      { label: "31 天", value: "B" },
      { label: "28 天", value: "C" },
      { label: "29 天", value: "D" },
    ],
    answer: "C",
  },
];

export default function ComparePage() {
  const topicId = "calendar";
  const [qIdx, setQIdx] = useState(0); // 0..2 答题中，3 = 完成
  const [selected, setSelected] = useState<string | null>(null);
  const [encourage, setEncourage] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  const qBoxRef = useRef<HTMLDivElement>(null);

  const isDone = qIdx >= QUESTIONS.length;
  const nextStep = getNextStep(topicId, "compare");

  const handleAnswer = (value: string) => {
    if (isDone) return;
    const cur = QUESTIONS[qIdx];
    setSelected(value);
    if (value === cur.answer) {
      setEncourage("");
      // 短暂展示选中态后进入下一题
      setTimeout(() => {
        if (qIdx >= QUESTIONS.length - 1) {
          setQIdx(QUESTIONS.length);
          setCompleteMsg(getRandomComplete());
        } else {
          setQIdx((i) => i + 1);
          setSelected(null);
        }
      }, 500);
    } else {
      setEncourage(getRandomEncourage());
      triggerShake(qBoxRef.current);
    }
  };

  return (
    <StepShell topicId={topicId} stepId="compare">
      <div className="space-y-6">
        {/* 12 个月天数表格 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <h2 className="text-lg font-bold text-[var(--text)]">
            12 个月的天数（平年）
          </h2>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            看看每个月有多少天，颜色一样表示天数相同
          </p>

          {/* 图例 */}
          <div className="mt-3 flex flex-wrap gap-3">
            {[
              { c: "var(--primary)", t: "31 天" },
              { c: "var(--accent2)", t: "30 天" },
              { c: "var(--signal-shake)", t: "2 月（特殊）" },
            ].map((l) => (
              <span
                key={l.t}
                className="flex items-center gap-1.5 rounded-full bg-[var(--bg-soft)] px-3 py-1 text-xs font-medium text-[var(--text-secondary)]"
              >
                <span
                  className="h-3 w-3 rounded-full"
                  style={{ backgroundColor: l.c }}
                />
                {l.t}
              </span>
            ))}
          </div>

          {/* 月份格子 */}
          <div className="mt-4 grid grid-cols-4 gap-2">
            {MONTHS_DAYS.map((info) => {
              const color = dayColor(info.days);
              return (
                <div
                  key={info.m}
                  className="flex flex-col items-center rounded-[var(--radius-sm)] p-3 text-white shadow-[var(--shadow-sm)]"
                  style={{ backgroundColor: color }}
                >
                  <span className="text-sm font-medium opacity-90">
                    {info.m}月
                  </span>
                  <span className="text-2xl font-extrabold leading-tight">
                    {info.days}
                  </span>
                  <span className="text-[10px] opacity-90">
                    {dayLabel(info.days)}
                  </span>
                </div>
              );
            })}
          </div>
        </div>

        {/* 答题区 */}
        {!isDone && (
          <div
            ref={qBoxRef}
            className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
          >
            <div className="mb-3 flex items-center justify-between">
              <span className="rounded-full bg-[var(--signal-focus)]/20 px-3 py-1 text-sm font-bold text-[var(--text)]">
                第 {qIdx + 1} / {QUESTIONS.length} 题
              </span>
              {encourage && (
                <span className="animate-float-in text-sm text-[var(--signal-shake)]">
                  {encourage}
                </span>
              )}
            </div>
            <p className="mb-4 text-center text-lg font-semibold text-[var(--text)]">
              {QUESTIONS[qIdx].q}
            </p>
            <div className="grid grid-cols-1 gap-3">
              {QUESTIONS[qIdx].options.map((opt) => {
                const isSel = selected === opt.value;
                return (
                  <button
                    key={opt.value}
                    onClick={() => handleAnswer(opt.value)}
                    className={`rounded-[var(--radius-sm)] border-2 px-4 py-3 text-left text-sm font-medium transition-all hover:-translate-y-0.5 ${
                      isSel
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                        : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--primary-light)]"
                    }`}
                  >
                    <span className="mr-2 font-bold text-[var(--primary)]">
                      {opt.value}.
                    </span>
                    {opt.label}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* 完成卡片 */}
        {isDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">⚖️</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              31 天的有 7 个月，30 天的有 4 个月，2 月最特别——平年只有 28 天。
            </p>
            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={() => {
                  setQIdx(0);
                  setSelected(null);
                  setEncourage("");
                  setCompleteMsg("");
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再做一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
